import React, { useEffect, useState } from 'react';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box, Typography, CircularProgress } from '@material-ui/core';
import { getCompanies, createCompany, updateCompany, deleteCompany } from '../services/ApiService';
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  root: {
    padding: theme.spacing(3),
  },
  form: {
    display: 'flex',
    gap: theme.spacing(2),
    marginBottom: theme.spacing(2),
  },
}));

export default function CompanyManagement() {
  const classes = useStyles();
  const [companies, setCompanies] = useState([]);
  const [newCompany, setNewCompany] = useState({ name: '', openingBalance: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    getCompanies().then(res => {
      if (res.error) {
        setError('Failed to load companies');
      } else {
        setCompanies(res.data);
      }
      setLoading(false);
    });
  }, []);

  const addCompany = () => {
    createCompany(newCompany).then(res => {
      if (!res.error) {
        setCompanies([...companies, res.data]);
        setNewCompany({ name: '', openingBalance: 0 });
      } else {
        setError('Failed to create company');
      }
    });
  };

  const handleUpdate = (id, company) => {
    updateCompany(id, company).then(res => {
      if (!res.error) {
        setCompanies(companies.map(c => (c.id === id ? res.data : c)));
      } else {
        setError('Failed to update company');
      }
    });
  };

  const handleDelete = (id) => {
    deleteCompany(id).then(res => {
      if (!res.error) {
        setCompanies(companies.filter(c => c.id !== id));
      } else {
        setError('Failed to delete company');
      }
    });
  };

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;

  return (
    <div className={classes.root}>
      <Typography variant="h4" gutterBottom>Company Management</Typography>
      <Box className={classes.form}>
        <TextField
          label="Company Name"
          value={newCompany.name}
          onChange={e => setNewCompany({ ...newCompany, name: e.target.value })}
        />
        <TextField
          label="Opening Balance"
          type="number"
          value={newCompany.openingBalance}
          onChange={e => setNewCompany({ ...newCompany, openingBalance: parseFloat(e.target.value) })}
        />
        <Button onClick={addCompany} color="primary" variant="contained">Add Company</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Opening Balance</TableCell>
            <TableCell>Closing Balance</TableCell>
            <TableCell>Due Amount</TableCell>
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {companies.map(company => (
            <TableRow key={company.id}>
              <TableCell>{company.name}</TableCell>
              <TableCell>{company.openingBalance}</TableCell>
              <TableCell>{company.closingBalance}</TableCell>
              <TableCell>{company.dueAmount}</TableCell>
              <TableCell>
                <Button onClick={() => handleUpdate(company.id, { ...company, name: company.name + ' Updated' })} color="primary">Update</Button>
                <Button onClick={() => handleDelete(company.id)} color="secondary">Delete</Button>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
